=FINAL LEGAL STRATEGY REVIEW — SENIOR PARTNER ANALYSIS

Case ID: {{ $json.case_id }}
Timestamp: {{ $json.timestamp }}

CLIENT:
{{ $json.user_name }}

LEGAL TOPIC (DOMAIN): {{ $json.legal_topic }}
LEGAL ISSUE: {{ $json.legal_issue }}
Urgency: {{ $json.urgency }}

RAW NARRATIVE:
{{ $json.legal_narrative || "No narrative" }}

--- LAWYER A (ADVOCATE) RECOMMENDATION ---
Strategy: {{ $json.lawyer_a.recommended_strategy || 'N/A' }}
Case Assessment: {{ $json.lawyer_a.case_assessment || 'N/A' }}
Legal Arguments:
{{ $json.lawyer_a.legal_arguments && $json.lawyer_a.legal_arguments.length ? $json.lawyer_a.legal_arguments.join('\n') : 'None' }}
Evidence Gaps:
{{ $json.lawyer_a.evidence_gaps && $json.lawyer_a.evidence_gaps.length ? $json.lawyer_a.evidence_gaps.join('\n') : 'None' }}
Win Probability (A's view): {{ $json.lawyer_a.win_probability || 'N/A' }}

--- LAWYER B (DEVIL'S ADVOCATE) CRITIQUE ---
Case Assessment: {{ $json.lawyer_b.case_assessment || 'N/A' }}
Counterarguments:
{{ $json.lawyer_b.legal_arguments && $json.lawyer_b.legal_arguments.length ? $json.lawyer_b.legal_arguments.join('\n') : 'None' }}
Evidence Attacks:
{{ $json.lawyer_b.evidence_attacks && $json.lawyer_b.evidence_attacks.length ? $json.lawyer_b.evidence_attacks.join('\n') : 'None' }}
Procedural Hazards:
{{ $json.lawyer_b.procedural_hazards && $json.lawyer_b.procedural_hazards.length ? $json.lawyer_b.procedural_hazards.join('\n') : 'None' }}
Win Probability (B's view): {{ $json.lawyer_b.win_probability || 'N/A' }} (client's chance of losing)

YOUR TASK AS SENIOR PARTNER:
This is a {{ $json.legal_topic }} case. Your analysis MUST stay within {{ $json.legal_topic }} law. Reject any arguments that borrow from unrelated practice areas.

1. DOMAIN CHECK: Before anything else, confirm: "This is a {{ $json.legal_topic }} matter. All analysis must use {{ $json.legal_topic }} statutes, rules, and jurisprudence."

2. Evaluate both lawyers. If either misapplies the law (e.g., uses labor concepts in a criminal case), explicitly note this in your notes and discount their argument.

3. Use the legal_db_search tool. Search queries MUST include "{{ $json.legal_topic }}" and the specific legal issue. Example: "{{ $json.legal_topic }} [specific issue] Philippines" or "criminal estafa jurisprudence".

4. Make the final call. Your recommendation must be a valid legal remedy for a {{ $json.legal_topic }} case.

Return ONLY valid JSON with these exact fields:
{
  "final_recommendation": "SETTLE|TRIAL|DEMAND_LETTER|MEDIATION|ADMINISTRATIVE_COMPLAINT|URGENT_PROTECTION_ORDER|DROP_CASE",
  "approved_strategy": "<comprehensive, detailed plan of action, at least several paragraphs, tailored to {{ $json.legal_topic }} law, including procedural steps, evidentiary requirements, and strategic considerations>",
  "win_probability": "STRONG|MODERATE|WEAK",
  "priority": "HIGH|MEDIUM|LOW",
  "notes": "<detailed and precise explanation, NOT brief. Include: (a) where lawyers agreed/disagreed with specific references, (b) any corrected misapplications of law, (c) why your recommendation is appropriate for a {{ $json.legal_topic }} case, (d) key supporting law or precedent found, (e) full legal reasoning and analysis, (f) discussion of evidence strengths/weaknesses, (g) procedural considerations, (h) risk assessment>"
}

Guidelines:
- If procedural hazards are fatal to a {{ $json.legal_topic }} case, DROP_CASE
- If settlement aligns with {{ $json.legal_topic }} remedies and risks high, SETTLE
- If {{ $json.legal_topic }} law supports going to trial and evidence is strong, TRIAL
- Demand letter/Mediation only if valid pre-litigation step in {{ $json.legal_topic }}
- URGENT_PROTECTION_ORDER only if safety/emergency context applies in {{ $json.legal_topic }} (e.g., family violence, not estafa)
- ADMINISTRATIVE_COMPLAINT only if government agency has exclusive jurisdiction over this {{ $json.legal_topic }} issue
- Base win_probability on the weakest points, but within the {{ $json.legal_topic }} framework

IMPORTANT: Your response must be ONLY the JSON object. No other text, explanations, or markdown. Begin your response with '{' and end with '}'.

parameters.jsCode:
// Senior Partner Parser (Strategist)
// Preserves all data for dashboard

const item = $input.first().json;
const intake = $('Analyst Webhook1').item.json.body || $('Analyst Webhook1').item.json;
const raw = (item.output || item.text || item.response || "").toString().trim();

if (!raw) {
  return [{
    json: {
      ...intake,
      senior_partner: {
        final_recommendation: "ANALYST_UNAVAILABLE",
        approved_strategy: "",
        win_probability: "UNKNOWN",
        priority: "UNKNOWN",
        notes: "Senior Partner analysis failed to produce response."
      },
      pipeline_status: 'ANALYST_FAILED'
    }
  }];
}

let cleaned = raw
  .replace(/```json\s*/gi, "")
  .replace(/```\s*/gi, "")
  .trim();

const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
if (jsonMatch) cleaned = jsonMatch[0];

let ai;
try {
  ai = JSON.parse(cleaned);
} catch (e) {
  return [{
    json: {
      ...intake,
      senior_partner: {
        final_recommendation: "PARSE_ERROR",
        approved_strategy: "",
        win_probability: "UNKNOWN",
        priority: "UNKNOWN",
        notes: `JSON parse failed: ${e.message}`
      },
      pipeline_status: 'ANALYST_FAILED'
    }
  }];
}

// Validate final_recommendation
const VALID_RECOMMENDATIONS = ['SETTLE', 'TRIAL', 'DEMAND_LETTER', 'MEDIATION', 'ADMINISTRATIVE_COMPLAINT', 'URGENT_PROTECTION_ORDER', 'DROP_CASE'];
const recommendation = VALID_RECOMMENDATIONS.includes(ai.final_recommendation) ? ai.final_recommendation : 'PENDING';

// Validate priority
const VALID_PRIORITIES = ['HIGH', 'MEDIUM', 'LOW'];
const priority = VALID_PRIORITIES.includes(ai.priority) ? ai.priority : 'MEDIUM';

return [{
  json: {
    // Preserve all fields
    case_id:             intake.case_id,
    timestamp:           intake.timestamp,
    submitted_by:        intake.submitted_by,
    user_name:           intake.user_name,
    contact_number:      intake.contact_number   || "",
    date_of_birth:       intake.date_of_birth    || "",
    civil_status:        intake.civil_status     || "",
    address:             intake.address          || "",
    occupation:          intake.occupation       || "",
    legal_topic:         intake.legal_topic      || "",
    legal_issue:         intake.legal_issue      || "",
    incident_date:       intake.incident_date    || "",
    opposing_party:      intake.opposing_party   || "",
    urgency:             intake.urgency          || "MEDIUM",
    legal_narrative:     intake.legal_narrative  || "",
    clerk_notes:         intake.clerk_notes      || "",
    ai_summary:          intake.ai_summary       || "",
    case_theory:         intake.case_theory      || "",
    documents_submitted: intake.documents_submitted || [],
    documents_needed:    intake.documents_needed    || [],
    attachments_meta:    intake.attachments_meta   || [],
    document_urls:       intake.document_urls      || [],
    lawyer_a:            intake.lawyer_a         || null,
    lawyer_b:            intake.lawyer_b         || null,

    // Senior Partner final analysis
    senior_partner: {
      final_recommendation: recommendation,
      approved_strategy:   ai.approved_strategy   || "",
      win_probability:     ai.win_probability     || "UNKNOWN",
      priority:            priority,
      notes:               ai.notes               || ""
    },

    pipeline_status: 'COMPLETE'
  }
}];
